import{_ as e,o as a,c as o,ag as i}from"./chunks/framework.Culc7SYV.js";const u=JSON.parse('{"title":"Companion Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"Companion-Configuration.md","filePath":"Companion-Configuration.md","lastUpdated":null}'),r={name:"Companion-Configuration.md"};function d(n,t,s,l,c,h){return a(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="companion-configuration" tabindex="-1">Companion Configuration <a class="header-anchor" href="#companion-configuration" aria-label="Permalink to &quot;Companion Configuration&quot;">​</a></h1><p>Last modified: 10/03/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Companion settings are grouped by mode so you can control privacy, prompts, and output behavior.</p><h2 id="core-settings" tabindex="-1">Core settings <a class="header-anchor" href="#core-settings" aria-label="Permalink to &quot;Core settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>What it controls</th></tr></thead><tbody><tr><td>Enable Companion</td><td>Turns companion features on/off globally</td></tr><tr><td>Modal widget - button visibility</td><td>Controls whether the bottom-right note trigger is hidden, shown on hover, or always visible</td></tr><tr><td>AI provider</td><td>Which backend receives requests</td></tr><tr><td>OpenRouter model access</td><td>For OpenRouter only: filters model catalog to Free or Paid options</td></tr><tr><td>Model</td><td>Model name used for requests</td></tr><tr><td>Endpoint override</td><td>Custom provider base URL (custom provider only)</td></tr><tr><td>API key</td><td>Provider credential stored locally</td></tr><tr><td>Save chat history</td><td>Restores prior Ask/Review chats per note</td></tr><tr><td>Sync delete/reset to provider</td><td>When supported, requests remote conversation deletion when you clear/reset chats</td></tr></tbody></table><h2 id="ask-mode-settings" tabindex="-1">Ask mode settings <a class="header-anchor" href="#ask-mode-settings" aria-label="Permalink to &quot;Ask mode settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>What it controls</th></tr></thead><tbody><tr><td>Custom instructions</td><td>Prompt rules for Ask responses</td></tr><tr><td>Include images from note in messages</td><td>Sends embedded images with Ask requests</td></tr></tbody></table><h2 id="review-mode-settings" tabindex="-1">Review mode settings <a class="header-anchor" href="#review-mode-settings" aria-label="Permalink to &quot;Review mode settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>What it controls</th></tr></thead><tbody><tr><td>Custom instructions</td><td>Prompt rules for Review responses</td></tr><tr><td>Include images from note in messages</td><td>Sends embedded images with Review requests</td></tr></tbody></table><h2 id="flashcard-mode-settings" tabindex="-1">Flashcard mode settings <a class="header-anchor" href="#flashcard-mode-settings" aria-label="Permalink to &quot;Flashcard mode settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>What it controls</th></tr></thead><tbody><tr><td>Custom instructions</td><td>Prompt rules for flashcard generation</td></tr><tr><td>Include images from note in messages</td><td>Sends embedded images for flashcard generation (vision-capable models required)</td></tr><tr><td>Approximate number of cards</td><td>Target count (1-10)</td></tr><tr><td>What flashcard types to generate</td><td>Enable/disable Basic, Reversed, Cloze, MCQ, Ordered, IO</td></tr><tr><td>Generated fields</td><td>Include/exclude <code>T</code>, <code>I</code>, and <code>G</code> output rows</td></tr></tbody></table><h3 id="model-image-capability-notes" tabindex="-1">Model image capability notes <a class="header-anchor" href="#model-image-capability-notes" aria-label="Permalink to &quot;Model image capability notes&quot;">​</a></h3><ul><li>Some models cannot analyse image content.</li><li>More advanced models can identify text in images and convert it into question cards.</li><li>The most advanced models may attempt to generate image occlusion (IO) cards.</li><li>IO mask positioning can still be imperfect, so open generated IO cards in the flashcard editor and verify mask placement before studying.</li></ul><h2 id="suggested-starting-profile" tabindex="-1">Suggested starting profile <a class="header-anchor" href="#suggested-starting-profile" aria-label="Permalink to &quot;Suggested starting profile&quot;">​</a></h2><ul><li>Keep card count low (3-5) while tuning prompts.</li><li>Start with text card types (Basic/Cloze) before enabling all types.</li><li>Keep image input disabled unless you are intentionally using a vision-capable model.</li><li>Keep custom instructions concise and test in one note first.</li></ul><h2 id="safety-and-policy" tabindex="-1">Safety and policy <a class="header-anchor" href="#safety-and-policy" aria-label="Permalink to &quot;Safety and policy&quot;">​</a></h2><p>All generated content should be reviewed before use. See <a href="./AI-Usage-Policy">AI Usage Policy</a>.</p>',18)])])}const p=e(r,[["render",d]]);export{u as __pageData,p as default};
